android.extraProguardRules:
# --- App-specific rules ---
-keep public class com.cardgameengine.host.** extends android.app.Application { *; }
-keep public class com.cardgameengine.host.** extends android.app.Activity { *; }

# --- NitroModules safety net (defense-in-depth) ---
-keep class com.margelo.nitro.** { *; }

# --- Hermes engine ---
-keep class com.facebook.hermes.unicode.** { *; }
-keep class com.facebook.jni.** { *; }

# --- Suppress warnings ---
-dontwarn com.facebook.react.flipper.**
-dontwarn com.facebook.jni.**

# --- react-native-svg (JNI reflection) ---
-keep class com.horcrux.svg.** { *; }
